    target_exam: body.target_exam || 'JEE/CET',
    query_type: body.query_type || 'General',
    message: body.message || '',
    status: 'Open',
    raised_at: now.toISOString(),
    raised_at_readable: now.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
