const params = $input.first().json.query || $input.first().json;
const score = parseInt(params.score || 3);
const ticketId = params.ticket || params.ticket_id || 'Unknown';
const now = new Date();
return [{
  json: {
    ticket_id: ticketId,
    satisfaction_score: score,
    score_label: score >= 4 ? 'Excellent' : score === 3 ? 'Neutral' : 'Poor',
    needs_followup: score <= 2,
    logged_at: now.toISOString(),
    logged_at_readable: now.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
    db_query: `UPDATE tickets SET satisfaction_score=${score}, status='Resolved' WHERE ticket_id='${ticketId}'`
  }
}];

